const now = new Date();
const options = { timeZone: 'Australia/Sydney' };
const monthName = now.toLocaleDateString('en-AU', { ...options, month: 'long' });
const year = now.toLocaleDateString('en-AU', { ...options, year: 'numeric' });
const weekNum = Math.ceil(now.getDate() / 7);
const weekLabel = `${year}-W${weekNum < 10 ? '0' : ''}${weekNum}`;

// Get match data from DB response
let activeSeries = 'Australian domestic cricket season';
try {
  const response = $input.first().json;
  const matches = (response.data || []).map(m => m.matchTitle).filter(Boolean);
  if (matches.length > 0) {
    activeSeries = matches.slice(0, 3).join(', ');
  }
} catch(e) { /* no cricket data */ }

// Determine cricket season context
const month = now.getMonth() + 1;
let season = '';
if (month >= 11 || month <= 2) season = 'Summer: BBL season, international Tests/ODIs active';
else if (month >= 9 && month <= 10) season = 'Spring: Pre-season, Sheffield Shield starting';
else if (month >= 3 && month <= 5) season = 'Autumn: End of season, club finals';
else season = 'Winter: Off-season, pre-season training, gear upgrades';

return [{
  json: {
    month: monthName,
    year: year,
    week_label: weekLabel,
    season_context: season,
    active_series: activeSeries,
    generated_at: now.toISOString()
  }
}];

const rawText = $input.first().json.text || $input.first().json.message?.content || '';
const cleaned = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) {
    try { parsed = JSON.parse(match[0]); }
    catch(e2) { throw new Error('Could not parse hashtag JSON: ' + cleaned.substring(0, 200)); }
  } else {
    throw new Error('Could not parse hashtag JSON: ' + cleaned.substring(0, 200));
  }
}

// Validate category counts
const expected = { brand: 5, product: 8, cricket: 8, regional: 5, trending: 4 };
for (const [cat, count] of Object.entries(expected)) {
  if (!Array.isArray(parsed[cat])) {
    throw new Error(`Missing category in GPT response: ${cat}`);
  }
  if (parsed[cat].length !== count) {
    throw new Error(`Category "${cat}" has ${parsed[cat].length} tags, expected ${count}`);
  }
}

const context = $('Build Context for GPT-4o').first().json;

return [{
  json: {
    brand: parsed.brand,
    product: parsed.product,
    cricket: parsed.cricket,
    regional: parsed.regional,
    trending: parsed.trending,
    week: context.week_label
  }
}];

const syncResponse = $input.first().json;
const context = $('Build Context for GPT-4o').first().json;
const parsed = $('Parse & Validate Hashtags').first().json;

return [{
  json: {
    count: syncResponse.count || 30,
    week: syncResponse.week || context.week_label,
    month: context.month,
    season: context.season_context,
    brand_count: (parsed.brand || []).length,
    product_count: (parsed.product || []).length,
    cricket_count: (parsed.cricket || []).length,
    regional_count: (parsed.regional || []).length,
    trending_count: (parsed.trending || []).length
  }
}];

